#include<cstdio>
#include<vector>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
inline int read()
{
    int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
    while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10,W=1e5;std::vector<int> D[N];bool S[N];
int n,mu[N],cnt[N],stk[N],top;bool vis[N];long long ans;
int main()
{
    n=read();rep(1,n,i){int x=read();S[x]=true;ans=max(ans,1ll*x);}
    mu[1]=1;rep(1,W,i)for(int j=i<<1;j<=W;j+=i)mu[j]-=mu[i];
    rep(1,W,i)for(int j=i;j<=W;j+=i){if(mu[i])D[j].push_back(i);S[i]|=S[j];}
    drep(W,1,x)if(S[x])
    {
        int cur=0;for(int d:D[x])cur+=mu[d]*cnt[d];
        while(cur)
        {
            int lst=cur;for(int d:D[stk[top]]){--cnt[d];if(x%d==0)cur-=mu[d];}
            if(cur!=lst)ans=max(ans,1ll*x*stk[top]);--top;
        }
        for(int d:D[x])++cnt[d];stk[++top]=x;
    }
    printf("%lld\n",ans);return 0;

}
